function active$CashFlowTypeForm(f) {f.add_onResponseComplete(on$CashFlowTypeForm$ResponseComplete);}
function close$CashFlowTypeForm(f) {try {f.remove_onResponseComplete(on$CashFlowTypeForm$ResponseComplete)} catch (ex) {}}
function on$CashFlowTypeForm$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_dot');
      break;
    default:
      break;
  }
}

      &ScriptIrregular;
